using CSharpLargeApi.Application.Interfaces;
using CSharpLargeApi.Infrastructure.External;
using CSharpLargeApi.Infrastructure.Persistence;
using CSharpLargeApi.Infrastructure.Services;

namespace CSharpLargeApi.Api.Extensions;

/// <summary>
/// Extension methods for configuring dependency injection services.
/// Registers all application, infrastructure, and external services.
/// </summary>
public static class ServiceCollectionExtensions
{
    /// <summary>
    /// Registers all application services with the DI container.
    /// </summary>
    public static void AddApplicationServices(this Dictionary<Type, object> services)
    {
        // External clients
        var stripeClient = new StripeClient("sk_test_placeholder");
        var sendGridClient = new SendGridClient("sg_test_placeholder");
        var redisClient = new RedisClient("localhost:6379");

        services[typeof(StripeClient)] = stripeClient;
        services[typeof(SendGridClient)] = sendGridClient;
        services[typeof(RedisClient)] = redisClient;

        // Persistence
        var dbContext = new AppDbContext();
        services[typeof(AppDbContext)] = dbContext;

        // Infrastructure services
        var cacheService = new CacheService(redisClient);
        services[typeof(ICacheService)] = cacheService;

        // Note: In a real app, these would be registered as scoped services
    }

    /// <summary>
    /// Registers all infrastructure services with the DI container.
    /// </summary>
    public static void AddInfrastructureServices(this Dictionary<Type, object> services)
    {
        // Repositories, services, and workers would be registered here
        // using the standard ASP.NET Core DI container pattern:
        // services.AddScoped<IPaymentService, PaymentService>();
        // services.AddScoped<IUserService, UserService>();
        // etc.
    }

    /// <summary>
    /// Configures CORS policy for the API.
    /// </summary>
    public static void AddCorsPolicy(this Dictionary<string, string[]> corsConfig)
    {
        corsConfig["AllowedOrigins"] = new[] { "https://app.example.com", "http://localhost:3000" };
        corsConfig["AllowedMethods"] = new[] { "GET", "POST", "PUT", "DELETE", "PATCH" };
        corsConfig["AllowedHeaders"] = new[] { "Authorization", "Content-Type", "X-Request-Id" };
    }
}

namespace CSharpLargeApi.Domain.Interfaces;

/// <summary>
/// Generic repository interface for aggregate root persistence.
/// Implementations live in the Infrastructure layer and use EF Core
/// or another ORM to fulfil the contract.
/// </summary>
/// <typeparam name="T">The aggregate root entity type.</typeparam>
public interface IRepository<T> where T : class, IAggregateRoot
{
    /// <summary>
    /// Retrieves an entity by its unique identifier.
    /// Returns null if no entity is found with the given ID.
    /// </summary>
    Task<T?> GetByIdAsync(Guid id, CancellationToken cancellationToken = default);

    /// <summary>
    /// Retrieves all entities of this type.
    /// Use sparingly — prefer filtered queries for large datasets.
    /// </summary>
    Task<IReadOnlyList<T>> GetAllAsync(CancellationToken cancellationToken = default);

    /// <summary>
    /// Adds a new entity to the repository.
    /// The entity is not persisted until SaveChangesAsync is called on the unit of work.
    /// </summary>
    Task<T> AddAsync(T entity, CancellationToken cancellationToken = default);

    /// <summary>
    /// Updates an existing entity in the repository.
    /// </summary>
    void Update(T entity);

    /// <summary>
    /// Removes an entity from the repository.
    /// </summary>
    void Delete(T entity);

    /// <summary>
    /// Persists all pending changes to the underlying store.
    /// </summary>
    Task<int> SaveChangesAsync(CancellationToken cancellationToken = default);
}

namespace CSharpLargeApi.Domain.Exceptions;

/// <summary>
/// Exception thrown when a requested entity cannot be found.
/// Typically maps to HTTP 404 at the API layer.
/// </summary>
public class EntityNotFoundException : DomainException
{
    /// <summary>
    /// Gets the type name of the entity that was not found.
    /// </summary>
    public string EntityType { get; }

    /// <summary>
    /// Gets the identifier that was used to look up the entity.
    /// </summary>
    public string EntityId { get; }

    /// <summary>
    /// Creates a new EntityNotFoundException for the given entity type and ID.
    /// </summary>
    public EntityNotFoundException(string entityType, string entityId)
        : base($"{entityType} with ID '{entityId}' was not found.", "ENTITY_NOT_FOUND")
    {
        EntityType = entityType;
        EntityId = entityId;
    }

    /// <summary>
    /// Creates a new EntityNotFoundException for the given entity type and GUID.
    /// </summary>
    public EntityNotFoundException(string entityType, Guid entityId)
        : this(entityType, entityId.ToString())
    {
    }

    /// <summary>
    /// Creates an EntityNotFoundException using the generic type parameter for the entity name.
    /// </summary>
    public static EntityNotFoundException For<T>(Guid id) where T : class
    {
        return new EntityNotFoundException(typeof(T).Name, id);
    }
}

