using CSharpLargeApi.Application.Interfaces;
using CSharpLargeApi.Domain.Entities;
using CSharpLargeApi.Domain.Exceptions;
using CSharpLargeApi.Domain.Interfaces;

namespace CSharpLargeApi.Infrastructure.Services;

/// <summary>
/// Generates and sends payment receipts by coordinating between the payment,
/// user, and notification services.
/// </summary>
public class PaymentReceiptService : IPaymentReceiptService
{
    private readonly IPaymentService _paymentService;
    private readonly IUserService _userService;
    private readonly INotificationService _notificationService;
    private readonly IRepository<PaymentReceipt> _receiptRepository;

    /// <summary>
    /// Initializes the service with the required dependencies.
    /// </summary>
    public PaymentReceiptService(
        IPaymentService paymentService,
        IUserService userService,
        INotificationService notificationService,
        IRepository<PaymentReceipt> receiptRepository)
    {
        _paymentService = paymentService ?? throw new ArgumentNullException(nameof(paymentService));
        _userService = userService ?? throw new ArgumentNullException(nameof(userService));
        _notificationService = notificationService ?? throw new ArgumentNullException(nameof(notificationService));
        _receiptRepository = receiptRepository ?? throw new ArgumentNullException(nameof(receiptRepository));
    }

    /// <summary>
    /// Creates a receipt record for the specified payment.
    /// </summary>
    public async Task<PaymentReceipt> GenerateReceipt(Guid paymentId, CancellationToken cancellationToken = default)
    {
        var payment = await _paymentService.GetPaymentAsync(paymentId, cancellationToken)
            ?? throw new EntityNotFoundException(nameof(Payment), paymentId);

        var paymentMethodDescription = payment.GatewayTransactionId is not null
            ? $"Transaction {payment.GatewayTransactionId}"
            : "Payment on file";

        var receipt = PaymentReceipt.Create(
            payment.Id,
            payment.UserId,
            payment.Amount,
            paymentMethodDescription);

        await _receiptRepository.AddAsync(receipt, cancellationToken);
        await _receiptRepository.SaveChangesAsync(cancellationToken);

        return receipt;
    }

    /// <summary>
    /// Generates a receipt for the specified payment and emails it to the user.
    /// </summary>
    public async Task SendReceipt(Guid paymentId, Guid userId, CancellationToken cancellationToken = default)
    {
        var receipt = await GenerateReceipt(paymentId, cancellationToken);

        var user = await _userService.GetUserAsync(userId, cancellationToken)
            ?? throw new EntityNotFoundException(nameof(User), userId);

        var subject = $"Your payment receipt – {receipt.ReceiptNumber}";
        var body = BuildReceiptEmailBody(receipt, user.DisplayName);

        await _notificationService.SendEmailAsync(userId, subject, body, cancellationToken);

        receipt.MarkAsSent();
        _receiptRepository.Update(receipt);
        await _receiptRepository.SaveChangesAsync(cancellationToken);
    }

    private static string BuildReceiptEmailBody(PaymentReceipt receipt, string displayName)
    {
        return $"""
            Dear {displayName},

            Thank you for your payment. Here is your receipt:

            Receipt Number : {receipt.ReceiptNumber}
            Date           : {receipt.CreatedAt:yyyy-MM-dd HH:mm} UTC
            Amount         : {receipt.Amount.Amount} {receipt.Amount.Currency}
            Payment Method : {receipt.PaymentMethodDescription}

            If you have any questions regarding this transaction, please contact our support team.

            Best regards,
            The Billing Team
            """;
    }
}
